import java.util.*;

class Excel {

    int[][] mat;
    Map<String, List<String>> formulas;

    public Excel(int height, char width) {
        mat = new int[height][width - 'A' + 1];
        formulas = new HashMap<>();
    }

    public void set(int row, char column, int val) {
        String pos = String.format("%c%d", column, row);
        formulas.remove(pos);
        mat[row - 1][column - 'A'] = val;
    }

    public int get(int row, char column) {
        String pos = String.format("%c%d", column, row);
        if (formulas.containsKey(pos)) {
            return sum(row, column, formulas.get(pos));
        }
        return mat[row - 1][column - 'A'];
    }

    public int sum(int row, char column, List<String> numbers) {
        int total = 0;
        for (String num : numbers) {
            if (num.contains(":")) {
                String[] parts = num.split(":");
                int startRow = Integer.parseInt(parts[0].substring(1));
                int endRow = Integer.parseInt(parts[1].substring(1));
                char startCol = parts[0].charAt(0);
                char endCol = parts[1].charAt(0);
                for (int r = startRow; r <= endRow; r++) {
                    for (char c = startCol; c <= endCol; c++) {
                        total += get(r, c);
                    }
                }
            } else {
                total += get(Integer.parseInt(num.substring(1)), num.charAt(0));
            }
        }
        set(row, column, total);
        formulas.put(String.format("%c%d", column, row), numbers);
        return total;
    }
}
